import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';
import campusBg from '../assets/vemu-campus.jpg';
import vemuLogo from '../assets/vemu-logo.jpg';

const loginStyles = `
  @keyframes loginCardIn {
    from { opacity: 0; transform: translateX(60px) scale(0.95); }
    to   { opacity: 1; transform: translateX(0)    scale(1);    }
  }
  @keyframes logoSpinIn {
    from { opacity: 0; transform: rotate(-15deg) scale(0.7); }
    to   { opacity: 1; transform: rotate(0deg)   scale(1);   }
  }
  @keyframes loginFadeUp {
    from { opacity: 0; transform: translateY(14px); }
    to   { opacity: 1; transform: translateY(0);    }
  }
  .login-card-anim    { animation: loginCardIn  0.65s cubic-bezier(0.34,1.56,0.64,1) both; }
  .login-logo-anim    { animation: logoSpinIn   0.6s  cubic-bezier(0.34,1.56,0.64,1) both; animation-delay:0.3s; }
  .login-title-anim   { animation: loginFadeUp  0.5s  ease both; animation-delay:0.4s; }
  .login-sub-anim     { animation: loginFadeUp  0.5s  ease both; animation-delay:0.5s; }
  .login-tabs-anim    { animation: loginFadeUp  0.45s ease both; animation-delay:0.55s; }
  .login-hint-anim    { animation: loginFadeUp  0.45s ease both; animation-delay:0.65s; }
  .login-field1-anim  { animation: loginFadeUp  0.45s ease both; animation-delay:0.70s; }
  .login-field2-anim  { animation: loginFadeUp  0.45s ease both; animation-delay:0.80s; }
  .login-btn-anim     { animation: loginFadeUp  0.45s ease both; animation-delay:0.90s; }
  .login-hint2-anim   { animation: loginFadeUp  0.45s ease both; animation-delay:1.00s; }
  .login-footer-anim  { animation: loginFadeUp  0.45s ease both; animation-delay:1.05s; }
`;

export default function Login() {
  const [activeTab,  setActiveTab]  = useState('Faculty');
  const [rollNumber, setRollNumber] = useState('');
  const [password,   setPassword]   = useState('');
  const [loading,    setLoading]    = useState(false);
  const { login } = useAuth();
  const navigate  = useNavigate();

  const roleRoutes = { admin: '/admin', hod: '/hod', faculty: '/faculty', student: '/student' };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!rollNumber.trim() || !password.trim()) { toast.error('Please enter roll number and password'); return; }
    setLoading(true);
    try {
      const tabType = activeTab === 'Student' ? 'student' : 'faculty';
      const user    = await login(rollNumber.trim(), password, tabType);
      toast.success(`Welcome, ${user.name}!`);
      navigate(roleRoutes[user.role] || '/');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed. Check your credentials.');
    } finally { setLoading(false); }
  };

  const handleTabChange = (tab) => { setActiveTab(tab); setRollNumber(''); setPassword(''); };

  const inputStyle = {
    width: '100%', padding: '12px 15px',
    background: 'rgba(255,255,255,0.88)',
    border: '2px solid rgba(0,0,0,0.25)',
    borderRadius: 10, fontSize: 14,
    fontWeight: 600, color: '#0f172a',
    outline: 'none', boxSizing: 'border-box',
    boxShadow: 'inset 0 2px 4px rgba(0,0,0,0.06)',
    transition: 'all 0.2s',
  };

  const labelStyle = {
    display: 'block', fontSize: 13.5, fontWeight: 800,
    color: '#0f172a', marginBottom: 7,
    textShadow: '0 1px 2px rgba(255,255,255,0.5)',
  };

  return (
    <div style={{
      position: 'fixed', inset: 0,
      backgroundImage: `url(${campusBg})`,
      backgroundSize: 'cover',
      backgroundPosition: 'center center',
      backgroundRepeat: 'no-repeat',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'flex-end',
      fontFamily: "'Segoe UI', system-ui, sans-serif",
      overflow: 'auto',
    }}>
      {/* Inject keyframes */}
      <style>{loginStyles}</style>

      {/* Login Card */}
      <div className="login-card-anim" style={{
        width: 400,
        minWidth: 340,
        maxWidth: '92vw',
        marginRight: '3%',
        background: 'rgba(255,255,255,0.35)',
        backdropFilter: 'blur(28px) saturate(180%)',
        WebkitBackdropFilter: 'blur(28px) saturate(180%)',
        border: '2.5px solid rgba(0,0,0,0.75)',
        borderRadius: 18,
        boxShadow: '0 0 0 1px rgba(0,0,0,0.5), 0 20px 60px rgba(0,0,0,0.40), inset 0 1px 0 rgba(255,255,255,0.5)',
        overflow: 'hidden',
        flexShrink: 0,
      }}>

        {/* Header */}
        <div style={{
          padding: '30px 28px 20px',
          textAlign: 'center',
          borderBottom: '2px solid rgba(0,0,0,0.20)',
          background: 'rgba(255,255,255,0.20)',
        }}>
          <div className="login-logo-anim" style={{
            width: 90, height: 90,
            borderRadius: '50%', overflow: 'hidden',
            margin: '0 auto 16px',
            border: '3px solid rgba(0,0,0,0.5)',
            boxShadow: '0 4px 20px rgba(0,0,0,0.35), 0 0 0 2px rgba(255,255,255,0.6)',
            background: 'white',
          }}>
            <img
              src={vemuLogo} alt="VEMU Logo"
              style={{ width: '100%', height: '100%', objectFit: 'cover', transition: 'transform 0.4s ease' }}
              onMouseEnter={e => { e.target.style.transform = 'scale(1.08) rotate(3deg)'; }}
              onMouseLeave={e => { e.target.style.transform = 'scale(1) rotate(0deg)'; }}
            />
          </div>

          <h1 className="login-title-anim" style={{
            fontSize: 21, fontWeight: 900, margin: '0 0 6px',
            color: '#0f172a',
            textShadow: '0 1px 0 rgba(255,255,255,0.8), 0 2px 6px rgba(0,0,0,0.15)',
          }}>
            VEMU Institute of Technology
          </h1>
          <p className="login-sub-anim" style={{
            fontSize: 12, margin: 0, color: '#1e293b',
            letterSpacing: 2.5, textTransform: 'uppercase', fontWeight: 800,
          }}>
            Student Mid Marks System
          </p>
        </div>

        {/* Tabs */}
        <div className="login-tabs-anim" style={{
          display: 'flex',
          borderBottom: '2px solid rgba(0,0,0,0.20)',
          background: 'rgba(0,0,0,0.08)',
        }}>
          {['Faculty','Student'].map(tab => (
            <button key={tab} onClick={() => handleTabChange(tab)} style={{
              flex: 1, padding: '13px 8px',
              border: 'none', cursor: 'pointer',
              fontSize: 14, fontWeight: 800,
              background: activeTab === tab ? 'rgba(255,255,255,0.45)' : 'transparent',
              color: activeTab === tab ? '#0f172a' : '#475569',
              borderBottom: `3px solid ${activeTab === tab ? '#0f172a' : 'transparent'}`,
              transition: 'all 0.2s', letterSpacing: 0.5,
            }}>
              {tab}
            </button>
          ))}
        </div>

        {/* Form body */}
        <div style={{ padding: '22px 26px 26px' }}>

          {/* Hint */}
          <div className="login-hint-anim" style={{
            background: 'rgba(255,255,255,0.40)',
            border: '1.5px solid rgba(0,0,0,0.18)',
            borderRadius: 9, padding: '9px 13px',
            fontSize: 12.5, marginBottom: 20,
            color: '#0f172a', textAlign: 'center', fontWeight: 700,
          }}>
            {activeTab === 'Student'
              ? '👨‍🎓 Students only — use your Roll Number'
              : '👩‍🏫 Faculty, HOD & Admin — use Employee ID'}
          </div>

          <form onSubmit={handleSubmit}>
            {/* Roll Number */}
            <div className="login-field1-anim" style={{ marginBottom: 16 }}>
              <label style={labelStyle}>
                {activeTab === 'Student' ? 'Roll Number' : 'Employee / Roll Number'}
              </label>
              <input
                type="text"
                placeholder={activeTab === 'Student' ? 'Enter your roll number' : 'Enter Staff ID / HOD ID / Admin ID'}
                value={rollNumber}
                onChange={e => setRollNumber(e.target.value)}
                autoFocus autoComplete="username"
                style={inputStyle}
                onFocus={e => { e.target.style.background = 'white'; e.target.style.borderColor = '#1a56db'; }}
                onBlur={e => { e.target.style.background = 'rgba(255,255,255,0.88)'; e.target.style.borderColor = 'rgba(0,0,0,0.25)'; }}
              />
            </div>

            {/* Password */}
            <div className="login-field2-anim" style={{ marginBottom: 22 }}>
              <label style={labelStyle}>Password</label>
              <input
                type="password"
                placeholder="Enter password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                autoComplete="current-password"
                style={inputStyle}
                onFocus={e => { e.target.style.background = 'white'; e.target.style.borderColor = '#1a56db'; }}
                onBlur={e => { e.target.style.background = 'rgba(255,255,255,0.88)'; e.target.style.borderColor = 'rgba(0,0,0,0.25)'; }}
              />
            </div>

            {/* Sign In */}
            <div className="login-btn-anim">
              <button
                type="submit" disabled={loading}
                style={{
                  width: '100%', padding: '14px',
                  background: loading ? 'rgba(255,255,255,0.5)' : 'rgba(255,255,255,0.90)',
                  border: '2px solid rgba(0,0,0,0.30)',
                  borderRadius: 10, fontSize: 16, fontWeight: 900,
                  color: '#1a56db', cursor: loading ? 'not-allowed' : 'pointer',
                  boxShadow: '0 4px 16px rgba(0,0,0,0.18)',
                  letterSpacing: 1.5, transition: 'all 0.2s',
                }}
                onMouseEnter={e => { if (!loading) { e.target.style.background = 'white'; e.target.style.transform = 'translateY(-2px)'; e.target.style.boxShadow = '0 6px 20px rgba(26,86,219,0.25)'; }}}
                onMouseLeave={e => { if (!loading) { e.target.style.background = 'rgba(255,255,255,0.90)'; e.target.style.transform = 'none'; e.target.style.boxShadow = '0 4px 16px rgba(0,0,0,0.18)'; }}}
              >
                {loading ? '⏳ Signing In...' : 'Sign In'}
              </button>
            </div>
          </form>

          <div className="login-hint2-anim" style={{
            textAlign: 'center', marginTop: 18,
            fontSize: 12.5, color: '#1e293b', fontWeight: 600,
          }}>
            Default password for new accounts:<br />
            <strong style={{ color: '#0f172a', fontSize: 13 }}>Your Roll Number</strong>
          </div>
        </div>

        {/* Footer */}
        <div className="login-footer-anim" style={{
          textAlign: 'center', padding: '12px 16px',
          background: 'rgba(0,0,0,0.12)',
          borderTop: '2px solid rgba(0,0,0,0.15)',
          fontSize: 11.5, color: '#1e293b',
          fontWeight: 700, letterSpacing: 0.3,
        }}>
          © 2024 VEMU Institute of Technology, P.Kothakota
        </div>
      </div>
    </div>
  );
}
